public String setToTemplateString(Set<String> mailMerges) {
    JSONArray result = new JSONArray();
    Set<String> createdCids = new HashSet<>();
    try {
        for(String cid: mailMerges) {
            if(createdCids.contains(cid)) continue;
            else createdCids.add(cid);
            
            result.put(cid);
        }
    } catch(Exception e) {
      e.printStackTrace();
    }
    return result.toString();
}


